mapper.select:
SELECT count(*) FROM st_course


        AND semester >= #{startTime}


        AND semester < #{endTime}

SELECT d.id, d.cnumber, d.semester, d.c_endingtime, c.title as cname, (SELECT GROUP_CONCAT(o.name) FROM st_orgcourse oc LEFT JOIN st_org o ON oc.orgid = o.id WHERE oc.courseid = d.cnumber) as org_name FROM st_course d LEFT JOIN st_content c ON d.conid = c.id
AND d.semester >= #{startTime}
AND d.semester < #{endTime}
ORDER BY d.cnumber DESC LIMIT #{offset}, #{limit}

SELECT count(a.sco_id)
FROM st_score a
LEFT JOIN st_course b ON a.cnumber = b.cnumber
WHERE a.snumber = #{uid}

    AND b.semester >= #{startTime}


    AND b.semester < #{endTime}

SELECT
b.conid, b.cnumber, b.semester,
b.cname, b.cdesc, b.c_endingtime,
a.sco_id, a.upload_file_name, a.total_points, a.degree_exp, a.degree_other,
ct.title as cname, ct.tid
FROM st_score a
LEFT JOIN st_course b ON a.cnumber = b.cnumber
left join `20230415`.st_content ct ON b.conid=ct.id
WHERE a.snumber = #{uid}

    AND b.semester >= #{startTime}


    AND b.semester < #{endTime}

ORDER BY b.semester DESC, a.sco_id DESC
LIMIT #{offset}, #{limit}

SELECT a.upload_file_name, a.snumber, u.name as sname, ct.title as cname
FROM st_score a LEFT JOIN st_user u ON a.snumber = u.uid LEFT JOIN st_course b ON a.cnumber = b.cnumber LEFT JOIN st_content ct ON b.conid = ct.id
WHERE a.sco_id IN  #{id}

SELECT a.upload_file_name, a.snumber, u.name as sname, ct.title as cname
FROM st_score a LEFT JOIN st_user u ON a.snumber = u.uid LEFT JOIN st_course b ON a.cnumber = b.cnumber LEFT JOIN st_content ct ON b.conid = ct.id
WHERE a.sco_id = #{scoId}

SELECT a.sco_id, a.snumber, a.total_points, u.name as sname, u.college, u.professional, ct.title as cname, b.semester,
(SELECT org.name FROM st_orgrole ogr LEFT JOIN st_org org ON ogr.orgid = org.id WHERE ogr.userid = a.snumber LIMIT 1) as class_name
FROM st_score a LEFT JOIN st_user u ON a.snumber = u.uid LEFT JOIN st_course b ON a.cnumber = b.cnumber LEFT JOIN st_content ct ON b.conid = ct.id

     AND b.semester = #{time} 

ORDER BY a.sco_id DESC LIMIT #{offset}, #{limit}
